SELECT COUNT(DISTINCT c.customer_id) AS total_customers
FROM customers c
JOIN customer_preferences cp ON c.customer_id = cp.customer_id;

SELECT SUM(c.total_spent) AS total_spent_in_default_currency
FROM customers AS c
WHERE c.currency_id = (SELECT currency_id FROM currencies WHERE is_default = 1);

SELECT product_name
FROM products
WHERE product_id = 0;

SELECT DISTINCT ps.size_id
FROM product_sizes ps
JOIN products p ON ps.product_id = p.product_id
WHERE p.category_id IN (
  SELECT category_id FROM categories WHERE category_name IN ('Tops', 'Bottoms')
) AND ps.is_out_of_stock = 0;
